// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

/**
 * Get packet type name from first byte
 */
export function getPacketType(typeByte: number): string {
  return PACKET_TYPE_MAP[typeByte] ?? 'UNKNOWN';
}

/**
 * Get packet type definition, handling aliases (BTN_* -> BTN)
 */
export function getPacketTypeDef(packetType: string): PacketTypeDef {
  // Direct match
  if (PACKET_TYPES[packetType]) {
    return PACKET_TYPES[packetType];
  }

  // Check for aliases
  if (packetType.startsWith('BTN_')) {
    return PACKET_TYPES.BTN;
  }
  if (packetType.startsWith('PAIR_B')) {
    return PACKET_TYPES.PAIR;
  }
  if (packetType.startsWith('BRIDGE_')) {
    return PACKET_TYPES.UNKNOWN;
  }

  return PACKET_TYPES.UNKNOWN;
}

/**
 * Get field color for a given format
 */
export function getFieldColor(format: FieldFormatType): string {
  return FIELD_FORMATS[format]?.color ?? '#9E9E9E';
}

/**
 * Parse a device ID from bytes
 */
export function parseDeviceId(bytes: string[], offset: number, endian: 'little' | 'big'): string {
  if (bytes.length < offset + 4) return '';
  const b = bytes.slice(offset, offset + 4);
  if (endian === 'little') {
    return `${b[3]}${b[2]}${b[1]}${b[0]}`.toUpperCase();
  }
  return `${b[0]}${b[1]}${b[2]}${b[3]}`.toUpperCase();
}

/**
 * Parse a level byte (0x00-0xFE = 0-100%)
 */
export function parseLevelByte(byte: string): string {
  const value = parseInt(byte, 16);
  if (value === 0) return '0%';
  const level = Math.round((value * 100) / 254);
  return `${level}%`;
}

/**
 * Parse a 16-bit level (0x0000-0xFEFF = 0-100%)
 */
export function parseLevel16bit(bytes: string[]): string {
  if (bytes.length < 2) return '';
  const value = parseInt(bytes[0] + bytes[1], 16);
  if (value === 0) return '0%';
  const level = Math.round((value * 100) / 65279);
  return `${level}%`;
}

/**
 * Get button name from code
 */
export function getButtonName(code: number): string {
  return BUTTON_NAMES[code] ?? `0x${code.toString(16).toUpperCase().padStart(2, '0')}`;
}

/**
 * Get action name from code
 */
export function getActionName(code: number): string {
  return ACTION_NAMES[code] ?? `0x${code.toString(16).toUpperCase().padStart(2, '0')}`;
}

/**
 * Parse a field value based on its format
 */
export function parseFieldValue(
  bytes: string[],
  offset: number,
  size: number,
  format: FieldFormatType
): { raw: string; decoded: string | null } {
  const fieldBytes = bytes.slice(offset, offset + size);
  const raw = fieldBytes.join(' ');

  if (fieldBytes.length === 0) {
    return { raw: '-', decoded: null };
  }

  let decoded: string | null = null;

  switch (format) {
    case 'device_id':
      if (fieldBytes.length >= 4) {
        decoded = parseDeviceId(bytes, offset, 'little');
      }
      break;
    case 'device_id_be':
      if (fieldBytes.length >= 4) {
        decoded = parseDeviceId(bytes, offset, 'big');
      }
      break;
    case 'level_byte':
      if (fieldBytes.length >= 1) {
        decoded = parseLevelByte(fieldBytes[0]);
      }
      break;
    case 'level_16bit':
      if (fieldBytes.length >= 2) {
        decoded = parseLevel16bit(fieldBytes);
      }
      break;
    case 'button':
      if (fieldBytes.length >= 1) {
        decoded = getButtonName(parseInt(fieldBytes[0], 16));
      }
      break;
    case 'action':
      if (fieldBytes.length >= 1) {
        decoded = getActionName(parseInt(fieldBytes[0], 16));
      }
      break;
    case 'decimal':
      if (fieldBytes.length >= 1) {
        decoded = String(parseInt(fieldBytes[0], 16));
      }
      break;
    // hex and crc: no decoded value, just raw
  }

  return { raw, decoded };
}
